<!DOCTYPE html>
<html lang="zh">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>乒乓球大战 - 双AI对手</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { 
            background: #1a1a2e; 
            display: flex; 
            justify-content: center; 
            align-items: center; 
            min-height: 100vh;
            font-family: Arial, sans-serif;
            overflow: hidden;
        }
        canvas { 
            max-width: 100%; 
            height: auto; 
            display: block; 
            margin: 0 auto; 
            border: 2px solid #e94560;
            border-radius: 4px;
        }
    </style>
</head>
<body>
    <canvas id="gameCanvas"></canvas>
    <script>
        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');
        canvas.width = 360;
        canvas.height = 640;

        // Game states
        const STATE_MENU = 0;
        const STATE_PLAYING = 1;
        const STATE_PAUSED = 2;
        const STATE_GAMEOVER = 3;

        let gameState = STATE_MENU;
        let selectedMode = 0; // 0: vs 1 AI, 1: vs 2 AI, 2: watch AI vs AI

        // Player paddle
        const player = {
            x: 150,
            y: 580,
            width: 80,
            height: 12,
            speed: 6,
            color: '#00d2ff',
            score: 0,
            lives: 3
        };

        // AI opponents
        const ai1 = {
            x: 150,
            y: 48,
            width: 80,
            height: 12,
            speed: 3.5,
            color: '#e94560',
            score: 0,
            difficulty: 0.85,
            targetX: 180,
            reactionDelay: 0,
            name: 'AI-红'
        };

        const ai2 = {
            x: 80,
            y: 300,
            width: 12,
            height: 80,
            speed: 3,
            color: '#ffc107',
            score: 0,
            difficulty: 0.75,
            targetY: 320,
            reactionDelay: 0,
            name: 'AI-金',
            isVertical: true
        };

        // Ball
        const ball = {
            x: 180,
            y: 320,
            radius: 8,
            speedX: 3,
            speedY: -4,
            maxSpeed: 8,
            color: '#ffffff',
            trail: []
        };

        // Particles
        let particles = [];
        let powerUps = [];
        let screenShake = 0;
        let comboCount = 0;
        let comboTimer = 0;
        let lastHitBy = '';

        // Input
        let keys = {};
        let touchX = null;
        let isDragging = false;

        // Mode settings
        let useAI2 = false;
        let playerControlled = true;

        document.addEventListener('keydown', (e) => {
            keys[e.key] = true;
            if (e.key === ' ' || e.key === 'Enter') {
                if (gameState === STATE_MENU) {
                    startGame();
                } else if (gameState === STATE_GAMEOVER) {
                    gameState = STATE_MENU;
                }
            }
            if (e.key === 'ArrowUp' && gameState === STATE_MENU) {
                selectedMode = (selectedMode - 1 + 3) % 3;
            }
            if (e.key === 'ArrowDown' && gameState === STATE_MENU) {
                selectedMode = (selectedMode + 1) % 3;
            }
        });

        document.addEventListener('keyup', (e) => keys[e.key] = false);

        canvas.addEventListener('touchstart', (e) => {
            e.preventDefault();
            const rect = canvas.getBoundingClientRect();
            const scaleX = canvas.width / rect.width;
            const scaleY = canvas.height / rect.height;
            const tx = (e.touches[0].clientX - rect.left) * scaleX;
            const ty = (e.touches[0].clientY - rect.top) * scaleY;

            if (gameState === STATE_MENU) {
                // Check menu buttons
                if (ty > 280 && ty < 320) { selectedMode = 0; startGame(); }
                else if (ty > 340 && ty < 380) { selectedMode = 1; startGame(); }
                else if (ty > 400 && ty < 440) { selectedMode = 2; startGame(); }
            } else if (gameState === STATE_GAMEOVER) {
                gameState = STATE_MENU;
            } else {
                isDragging = true;
                touchX = tx;
            }
        });

        canvas.addEventListener('touchmove', (e) => {
            e.preventDefault();
            if (isDragging) {
                const rect = canvas.getBoundingClientRect();
                const scaleX = canvas.width / rect.width;
                touchX = (e.touches[0].clientX - rect.left) * scaleX;
            }
        });

        canvas.addEventListener('touchend', (e) => {
            e.preventDefault();
            isDragging = false;
            touchX = null;
        });

        canvas.addEventListener('mousedown', (e) => {
            const rect = canvas.getBoundingClientRect();
            const scaleX = canvas.width / rect.width;
            const scaleY = canvas.height / rect.height;
            const mx = (e.clientX - rect.left) * scaleX;
            const my = (e.clientY - rect.top) * scaleY;

            if (gameState === STATE_MENU) {
                if (my > 280 && my < 320) { selectedMode = 0; startGame(); }
                else if (my > 340 && my < 380) { selectedMode = 1; startGame(); }
                else if (my > 400 && my < 440) { selectedMode = 2; startGame(); }
            } else if (gameState === STATE_GAMEOVER) {
                gameState = STATE_MENU;
            } else {
                isDragging = true;
                touchX = mx;
            }
        });

        canvas.addEventListener('mousemove', (e) => {
            if (isDragging && gameState === STATE_PLAYING) {
                const rect = canvas.getBoundingClientRect();
                const scaleX = canvas.width / rect.width;
                touchX = (e.clientX - rect.left) * scaleX;
            }
        });

        canvas.addEventListener('mouseup', () => {
            isDragging = false;
            touchX = null;
        });

        function startGame() {
            useAI2 = selectedMode >= 1;
            playerControlled = selectedMode !== 2;

            player.score = 0;
            player.lives = 3;
            player.x = 150;
            ai1.score = 0;
            ai1.x = 150;
            ai2.score = 0;
            ai2.y = 280;

            if (selectedMode === 2) {
                // AI vs AI mode - player paddle becomes AI controlled
                player.color = '#00ff88';
            } else {
                player.color = '#00d2ff';
            }

            resetBall();
            particles = [];
            powerUps = [];
            comboCount = 0;
            comboTimer = 0;
            gameState = STATE_PLAYING;
        }

        function resetBall() {
            ball.x = 180;
            ball.y = 320;
            const angle = (Math.random() * 0.5 + 0.25) * Math.PI;
            const dir = Math.random() > 0.5 ? 1 : -1;
            ball.speedX = Math.cos(angle) * 4 * dir;
            ball.speedY = (Math.random() > 0.5 ? -1 : 1) * Math.abs(Math.sin(angle) * 4);
            ball.trail = [];
            comboCount = 0;
        }

        function createParticles(x, y, color, count) {
            for (let i = 0; i < count; i++) {
                particles.push({
                    x, y,
                    vx: (Math.random() - 0.5) * 8,
                    vy: (Math.random() - 0.5) * 8,
                    life: 1,
                    decay: Math.random() * 0.03 + 0.02,
                    size: Math.random() * 4 + 2,
                    color
                });
            }
        }

        function createScorePopup(x, y, text, color) {
            particles.push({
                x, y,
                vx: 0,
                vy: -2,
                life: 1,
                decay: 0.015,
                size: 0,
                color,
                text,
                isText: true
            });
        }

        function spawnPowerUp() {
            if (powerUps.length < 2 && Math.random() < 0.005) {
                const types = ['expand', 'shrink', 'fast', 'slow'];
                powerUps.push({
                    x: Math.random() * 280 + 40,
                    y: Math.random() * 300 + 150,
                    radius: 12,
                    type: types[Math.floor(Math.random() * types.length)],
                    life: 300,
                    pulse: 0
                });
            }
        }

        function updateAI(aiPaddle, isVertical) {
            if (isVertical) {
                // AI2 is a vertical paddle on the left side
                aiPaddle.reactionDelay--;
                if (aiPaddle.reactionDelay <= 0) {
                    aiPaddle.targetY = ball.y - aiPaddle.height / 2;
                    aiPaddle.targetY += (Math.random() - 0.5) * 30;
                    aiPaddle.reactionDelay = Math.floor(Math.random() * 8) + 3;
                }

                const targetCenter = aiPaddle.targetY + aiPaddle.height / 2;
                const currentCenter = aiPaddle.y + aiPaddle.height / 2;
                const diff = targetCenter - currentCenter;

                if (Math.abs(diff) > 2) {
                    aiPaddle.y += Math.sign(diff) * Math.min(Math.abs(diff) * aiPaddle.difficulty, aiPaddle.speed);
                }

                aiPaddle.y = Math.max(70, Math.min(canvas.height - 70 - aiPaddle.height, aiPaddle.y));
            } else {
                // AI1 is horizontal at top
                aiPaddle.reactionDelay--;
                if (aiPaddle.reactionDelay <= 0) {
                    // Predict ball position
                    let predictX = ball.x;
                    if (ball.speedY < 0) {
                        const timeToReach = (ball.y - aiPaddle.y) / (-ball.speedY);
                        predictX = ball.x + ball.speedX * timeToReach;
                        // Account for wall bounces
                        while (predictX < 0 || predictX > canvas.width) {
                            if (predictX < 0) predictX = -predictX;
                            if (predictX > canvas.width) predictX = 2 * canvas.width - predictX;
                        }
                    }
                    aiPaddle.targetX = predictX - aiPaddle.width / 2;
                    aiPaddle.targetX += (Math.random() - 0.5) * 20;
                    aiPaddle.reactionDelay = Math.floor(Math.random() * 6) + 2;
                }

                const diff = aiPaddle.targetX - aiPaddle.x;
                if (Math.abs(diff) > 2) {
                    aiPaddle.x += Math.sign(diff) * Math.min(Math.abs(diff) * aiPaddle.difficulty, aiPaddle.speed);
                }

                let minX = useAI2 ? ai2.x + ai2.width + 5 : 0;
                aiPaddle.x = Math.max(minX, Math.min(canvas.width - aiPaddle.width, aiPaddle.x));
            }
        }

        function updatePlayerAI() {
            // Auto-play for AI vs AI mode
            let predictX = ball.x;
            if (ball.speedY > 0) {
                const timeToReach = (player.y - ball.y) / ball.speedY;
                predictX = ball.x + ball.speedX * timeToReach;
                while (predictX < 0 || predictX > canvas.width) {
                    if (predictX < 0) predictX = -predictX;
                    if (predictX > canvas.width) predictX = 2 * canvas.width - predictX;
                }
            }
            const targetX = predictX - player.width / 2 + (Math.random() - 0.5) * 10;
            const diff = targetX - player.x;
            if (Math.abs(diff) > 2) {
                player.x += Math.sign(diff) * Math.min(Math.abs(diff) * 0.9, 5);
            }
            let minX = useAI2 ? ai2.x + ai2.width + 5 : 0;
            player.x = Math.max(minX, Math.min(canvas.width - player.width, player.x));
        }

        function update() {
            if (gameState !== STATE_PLAYING) return;

            // Update combo timer
            if (comboTimer > 0) comboTimer--;
            if (comboTimer === 0) comboCount = 0;

            // Player movement
            if (playerControlled) {
                if (touchX !== null) {
                    const targetX = touchX - player.width / 2;
                    player.x += (targetX - player.x) * 0.3;
                } else {
                    if (keys['ArrowLeft'] || keys['a']) player.x -= player.speed;
                    if (keys['ArrowRight'] || keys['d']) player.x += player.speed;
                }
                let minX = useAI2 ? ai2.x + ai2.width + 5 : 0;
                player.x = Math.max(minX, Math.min(canvas.width - player.width, player.x));
            } else {
                updatePlayerAI();
            }

            // Update AIs
            updateAI(ai1, false);
            if (useAI2) updateAI(ai2, true);

            // Ball trail
            ball.trail.push({ x: ball.x, y: ball.y });
            if (ball.trail.length > 15) ball.trail.shift();

            // Move ball
            ball.x += ball.speedX;
            ball.y += ball.speedY;

            // Wall collisions (right wall, and left wall if no AI2)
            if (ball.x + ball.radius > canvas.width) {
                ball.x = canvas.width - ball.radius;
                ball.speedX *= -1;
                createParticles(ball.x, ball.y, '#ffffff', 5);
            }

            if (useAI2) {
                // Left wall - AI2 misses = point for player
                if (ball.x - ball.radius < 0) {
                    ball.x = ball.radius;
                    ball.speedX *= -1;
                    player.score += 2;
                    createParticles(ball.x, ball.y, player.color, 10);
                    createScorePopup(ball.x, ball.y, '+2', player.color);
                }
            } else {
                if (ball.x - ball.radius < 0) {
                    ball.x = ball.radius;
                    ball.speedX *= -1;
                    createParticles(ball.x, ball.y, '#ffffff', 5);
                }
            }

            // AI2 vertical paddle collision
            if (useAI2) {
                if (ball.x - ball.radius < ai2.x + ai2.width &&
                    ball.x + ball.radius > ai2.x &&
                    ball.y > ai2.y && ball.y < ai2.y + ai2.height &&
                    ball.speedX < 0) {
                    ball.x = ai2.x + ai2.width + ball.radius;
                    ball.speedX = Math.abs(ball.speedX) * 1.05;

                    const hitPos = (ball.y - ai2.y) / ai2.height;
                    ball.speedY = (hitPos - 0.5) * 8;

                    clampBallSpeed();
                    createParticles(ball.x, ball.y, ai2.color, 8);
                    screenShake = 3;
                    ai2.score++;
                    lastHitBy = ai2.name;
                }
            }

            // Top - AI1 paddle collision
            if (ball.y - ball.radius < ai1.y + ai1.height &&
                ball.y + ball.radius > ai1.y &&
                ball.x > ai1.x && ball.x < ai1.x + ai1.width &&
                ball.speedY < 0) {
                ball.y = ai1.y + ai1.height + ball.radius;
                ball.speedY = Math.abs(ball.speedY) * 1.05;

                const hitPos = (ball.x - ai1.x) / ai1.width;
                ball.speedX = (hitPos - 0.5) * 8;

                clampBallSpeed();
                createParticles(ball.x, ball.y, ai1.color, 8);
                screenShake = 3;
                ai1.score++;
                lastHitBy = ai1.name;
            }

            // Bottom - Player paddle collision
            if (ball.y + ball.radius > player.y &&
                ball.y - ball.radius < player.y + player.height &&
                ball.x > player.x && ball.x < player.x + player.width &&
                ball.speedY > 0) {
                ball.y = player.y - ball.radius;
                ball.speedY = -Math.abs(ball.speedY) * 1.05;

                const hitPos = (ball.x - player.x) / player.width;
                ball.speedX = (hitPos - 0.5) * 8;

                clampBallSpeed();

                comboCount++;
                comboTimer = 120;
                const points = comboCount;
                player.score += points;

                createParticles(ball.x, ball.y, player.color, 10);
                if (comboCount > 1) {
                    createScorePopup(ball.x, ball.y - 20, `+${points} x${comboCount}`, '#ffff00');
                } else {
                    createScorePopup(ball.x, ball.y - 20, `+${points}`, player.color);
                }
                screenShake = 4;
                lastHitBy = '玩家';
            }

            // Ball out top (AI1 missed)
            if (ball.y - ball.radius < 0) {
                player.score += 5;
                createScorePopup(180, 100, '+5 得分!', '#00ff00');
                createParticles(ball.x, 10, '#00ff00', 20);
                resetBall();
            }

            // Ball out bottom (Player missed)
            if (ball.y + ball.radius > canvas.height) {
                player.lives--;
                ai1.score += 3;
                if (useAI2) ai2.score += 1;
                createParticles(ball.x, canvas.height - 10, '#ff0000', 20);
                screenShake = 8;

                if (player.lives <= 0) {
                    gameState = STATE_GAMEOVER;
                } else {
                    resetBall();
                }
            }

            // Power-ups
            spawnPowerUp();
            for (let i = powerUps.length - 1; i >= 0; i--) {
                const pu = powerUps[i];
                pu.life--;
                pu.pulse += 0.1;

                if (pu.life <= 0) {
                    powerUps.splice(i, 1);
                    continue;
                }

                const dx = ball.x - pu.x;
                const dy = ball.y - pu.y;
                if (Math.sqrt(dx * dx + dy * dy) < ball.radius + pu.radius) {
                    applyPowerUp(pu.type);
                    createParticles(pu.x, pu.y, '#ffff00', 15);
                    powerUps.splice(i, 1);
                }
            }

            // Update particles
            for (let i = particles.length - 1; i >= 0; i--) {
                const p = particles[i];
                p.x += p.vx;
                p.y += p.vy;
                p.life -= p.decay;
                if (!p.isText) {
                    p.vx *= 0.98;
                    p.vy *= 0.98;
                }
                if (p.life <= 0) particles.splice(i, 1);
            }

            // Screen shake decay
            if (screenShake > 0) screenShake *= 0.8;
            if (screenShake < 0.5) screenShake = 0;
        }

        function clampBallSpeed() {
            const speed = Math.sqrt(ball.speedX * ball.speedX + ball.speedY * ball.speedY);
            if (speed > ball.maxSpeed) {
                ball.speedX = (ball.speedX / speed) * ball.maxSpeed;
                ball.speedY = (ball.speedY / speed) * ball.maxSpeed;
            }
            // Ensure minimum vertical speed
            if (Math.abs(ball.speedY) < 2) {
                ball.speedY = ball.speedY > 0 ? 2 : -2;
            }
        }

        function applyPowerUp(type) {
            switch (type) {
                case 'expand':
                    player.width = Math.min(140, player.width + 20);
                    setTimeout(() => player.width = 80, 5000);
                    createScorePopup(180, 400, '扩大!', '#00ff00');
                    break;
                case 'shrink':
                    ai1.width = Math.max(40, ai1.width - 20);
                    setTimeout(() => ai1.width = 80, 5000);
                    createScorePopup(180, 200, 'AI缩小!', '#ff0000');
                    break;
                case 'fast':
                    const speed = Math.sqrt(ball.speedX * ball.speedX + ball.speedY * ball.speedY);
                    ball.speedX *= 1.3;
                    ball.speedY *= 1.3;
                    createScorePopup(180, 300, '加速!', '#ff8800');
                    break;
                case 'slow':
                    ball.speedX *= 0.7;
                    ball.speedY *= 0.7;
                    createScorePopup(180, 300, '减速!', '#8800ff');
                    break;
            }
        }

        function drawGlowRect(x, y, w, h, color, glowSize) {
            ctx.shadowColor = color;
            ctx.shadowBlur = glowSize || 15;
            ctx.fillStyle = color;
            ctx.fillRect(x, y, w, h);
            ctx.shadowBlur = 0;
        }

        function drawGlowCircle(x, y, r, color) {
            ctx.shadowColor = color;
            ctx.shadowBlur = 20;
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.arc(x, y, r, 0, Math.PI * 2);
            ctx.fill();
            ctx.shadowBlur = 0;
        }

        function draw() {
            ctx.save();

            // Screen shake
            if (screenShake > 0) {
                ctx.translate(
                    (Math.random() - 0.5) * screenShake * 2,
                    (Math.random() - 0.5) * screenShake * 2
                );
            }

            // Background
            ctx.fillStyle = '#0f0f23';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Grid lines
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
            ctx.lineWidth = 1;
            for (let i = 0; i < canvas.width; i += 30) {
                ctx.beginPath();
                ctx.moveTo(i, 0);
                ctx.lineTo(i, canvas.height);
                ctx.stroke();
            }
            for (let i = 0; i < canvas.height; i += 30) {
                ctx.beginPath();
                ctx.moveTo(0, i);
                ctx.lineTo(canvas.width, i);
                ctx.stroke();
            }

            // Center line
            ctx.setLineDash([8, 8]);
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(0, canvas.height / 2);
            ctx.lineTo(canvas.width, canvas.height / 2);
            ctx.stroke();
            ctx.setLineDash([]);

            if (gameState === STATE_MENU) {
                drawMenu();
            } else if (gameState === STATE_PLAYING || gameState === STATE_GAMEOVER) {
                drawGame();
            }

            ctx.restore();
        }

        function drawMenu() {
            // Title
            ctx.fillStyle = '#e94560';
            ctx.font = 'bold 42px Arial';
            ctx.textAlign = 'center';
            ctx.shadowColor = '#e94560';
            ctx.shadowBlur = 20;
            ctx.fillText('⚡ 乒乓大战 ⚡', 180, 120);
            ctx.shadowBlur = 0;

            ctx.fillStyle = '#aaa';
            ctx.font = '16px Arial';
            ctx.fillText('选择游戏模式', 180, 170);

            // Animated ball
            const t = Date.now() / 1000;
            drawGlowCircle(180 + Math.sin(t * 2) * 50, 220 + Math.cos(t * 3) * 20, 8, '#ffffff');

            // Mode buttons
            const modes = [
                { text: '🎮 对战 1个AI', desc: '经典模式', color: '#e94560' },
                { text: '🎮 对战 2个AI', desc: '挑战模式 - 侧面AI', color: '#ffc107' },
                { text: '🤖 观看 AI对战', desc: '观赏模式', color: '#00ff88' }
            ];

            modes.forEach((mode, i) => {
                const y = 280 + i * 60;
                const isHover = selectedMode === i;

                ctx.fillStyle = isHover ? mode.color + '33' : 'rgba(255,255,255,0.05)';
                ctx.strokeStyle = isHover ? mode.color : 'rgba(255,255,255,0.2)';
                ctx.lineWidth = 2;

                // Rounded rect
                const rx = 40, ry = y, rw = 280, rh = 44, rr = 8;
                ctx.beginPath();
                ctx.moveTo(rx + rr, ry);
                ctx.lineTo(rx + rw - rr, ry);
                ctx.quadraticCurveTo(rx + rw, ry, rx + rw, ry + rr);
                ctx.lineTo(rx + rw, ry + rh - rr);
                ctx.quadraticCurveTo(rx + rw, ry + rh, rx + rw - rr, ry + rh);
                ctx.lineTo(rx + rr, ry + rh);
                ctx.quadraticCurveTo(rx, ry + rh, rx, ry + rh - rr);
                ctx.lineTo(rx, ry + rr);
                ctx.quadraticCurveTo(rx, ry, rx + rr, ry);
                ctx.closePath();
                ctx.fill();
                ctx.stroke();

                ctx.fillStyle = isHover ? mode.color : '#ffffff';
                ctx.font = 'bold 18px Arial';
                ctx.fillText(mode.text, 180, y + 22);
                ctx.fillStyle = '#888';
                ctx.font = '12px Arial';
                ctx.fillText(mode.desc, 180, y + 38);
            });

            // Instructions
            ctx.fillStyle = '#666';
            ctx.font = '14px Arial';
            ctx.fillText('← → 或触摸移动挡板', 180, 500);
            ctx.fillText('↑↓ 选择模式 | 空格/回车 开始', 180, 525);
            ctx.fillText('点击按钮开始游戏', 180, 550);
        }

        function drawGame() {
            // Ball trail
            ball.trail.forEach((pos, i) => {
                const alpha = i / ball.trail.length * 0.4;
                ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
                ctx.beginPath();
                ctx.arc(pos.x, pos.y, ball.radius * (i / ball.trail.length), 0, Math.PI * 2);
                ctx.fill();
            });

            // Ball
            drawGlowCircle(ball.x, ball.y, ball.radius, ball.color);

            // Player paddle
            drawGlowRect(player.x, player.y, player.width, player.height, player.color);
            // Paddle edge highlight
            ctx.fillStyle = 'rgba(255,255,255,0.3)';
            ctx.fillRect(player.x, player.y, player.width, 2);

            // AI1 paddle
            drawGlowRect(ai1.x, ai1.y, ai1.width, ai1.height, ai1.color);
            ctx.fillStyle = 'rgba(255,255,255,0.3)';
            ctx.fillRect(ai1.x, ai1.y + ai1.height - 2, ai1.width, 2);

            // AI2 paddle (if active)
