                    ai1.width = Math.max(40, ai1.width - 20);
                    setTimeout(() => ai1.width = 80, 5000);
                    createScorePopup(180, 200, 'AI缩小!', '#ff0000');
                    break;
                case 'fast':
                    const speed = Math.sqrt(ball.speedX * ball.speedX + ball.speedY * ball.speedY);
                    ball.speedX *= 1.3;
                    ball.speedY *= 1.3;
                    createScorePopup(180, 300, '加速!', '#ff8800');
                    break;
                case 'slow':
                    ball.speedX *= 0.7;
                    ball.speedY *= 0.7;
                    createScorePopup(180, 300, '减速!', '#8800ff');
                    break;
            }
        }

        function drawGlowRect(x, y, w, h, color, glowSize) {
            ctx.shadowColor = color;
            ctx.shadowBlur = glowSize || 15;
            ctx.fillStyle = color;
            ctx.fillRect(x, y, w, h);
            ctx.shadowBlur = 0;
        }

        function drawGlowCircle(x, y, r, color) {
            ctx.shadowColor = color;
            ctx.shadowBlur = 20;
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.arc(x, y, r, 0, Math.PI * 2);
            ctx.fill();
            ctx.shadowBlur = 0;
        }

        function draw() {
            ctx.save();

            // Screen shake
            if (screenShake > 0) {
                ctx.translate(
                    (Math.random() - 0.5) * screenShake * 2,
                    (Math.random() - 0.5) * screenShake * 2
                );
            }

            // Background
            ctx.fillStyle = '#0f0f23';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Grid lines
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
            ctx.lineWidth = 1;
            for (let i = 0; i < canvas.width; i += 30) {
                ctx.beginPath();
                ctx.moveTo(i, 0);
                ctx.lineTo(i, canvas.height);
                ctx.stroke();
            }
            for (let i = 0; i < canvas.height; i += 30) {
                ctx.beginPath();
                ctx.moveTo(0, i);
                ctx.lineTo(canvas.width, i);
                ctx.stroke();
            }

            // Center line
            ctx.setLineDash([8, 8]);
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(0, canvas.height / 2);
            ctx.lineTo(canvas.width, canvas.height / 2);
            ctx.stroke();
            ctx.setLineDash([]);

            if (gameState === STATE_MENU) {
                drawMenu();
            } else if (gameState === STATE_PLAYING || gameState === STATE_GAMEOVER) {
                drawGame();
            }

            ctx.restore();
        }

        function drawMenu() {
            // Title
            ctx.fillStyle = '#e94560';
            ctx.font = 'bold 42px Arial';
            ctx.textAlign = 'center';
            ctx.shadowColor = '#e94560';
            ctx.shadowBlur = 20;
            ctx.fillText('⚡ 乒乓大战 ⚡', 180, 120);
            ctx.shadowBlur = 0;

            ctx.fillStyle = '#aaa';
            ctx.font = '16px Arial';
            ctx.fillText('选择游戏模式', 180, 170);

            // Animated ball
            const t = Date.now() / 1000;
            drawGlowCircle(180 + Math.sin(t * 2) * 50, 220 + Math.cos(t * 3) * 20, 8, '#ffffff');

            // Mode buttons
            const modes = [
                { text: '🎮 对战 1个AI', desc: '经典模式', color: '#e94560' },
                { text: '🎮 对战 2个AI', desc: '挑战模式 - 侧面AI', color: '#ffc107' },
                { text: '🤖 观看 AI对战', desc: '观赏模式', color: '#00ff88' }
            ];

            modes.forEach((mode, i) => {
                const y = 280 + i * 60;
                const isHover = selectedMode === i;

                ctx.fillStyle = isHover ? mode.color + '33' : 'rgba(255,255,255,0.05)';
                ctx.strokeStyle = isHover ? mode.color : 'rgba(255,255,255,0.2)';
                ctx.lineWidth = 2;

                // Rounded rect
                const rx = 40, ry = y, rw = 280, rh = 44, rr = 8;
                ctx.beginPath();
                ctx.moveTo(rx + rr, ry);
                ctx.lineTo(rx + rw - rr, ry);
                ctx.quadraticCurveTo(rx + rw, ry, rx + rw, ry + rr);
                ctx.lineTo(rx + rw, ry + rh - rr);
                ctx.quadraticCurveTo(rx + rw, ry + rh, rx + rw - rr, ry + rh);
                ctx.lineTo(rx + rr, ry + rh);
                ctx.quadraticCurveTo(rx, ry + rh, rx, ry + rh - rr);
                ctx.lineTo(rx, ry + rr);
                ctx.quadraticCurveTo(rx, ry, rx + rr, ry);
                ctx.closePath();
                ctx.fill();
                ctx.stroke();

                ctx.fillStyle = isHover ? mode.color : '#ffffff';
                ctx.font = 'bold 18px Arial';
                ctx.fillText(mode.text, 180, y + 22);
                ctx.fillStyle = '#888';
                ctx.font = '12px Arial';
                ctx.fillText(mode.desc, 180, y + 38);
            });

            // Instructions
            ctx.fillStyle = '#666';
            ctx.font = '14px Arial';
            ctx.fillText('← → 或触摸移动挡板', 180, 500);
            ctx.fillText('↑↓ 选择模式 | 空格/回车 开始', 180, 525);
            ctx.fillText('点击按钮开始游戏', 180, 550);
        }

        function drawGame() {
            // Ball trail
            ball.trail.forEach((pos, i) => {
                const alpha = i / ball.trail.length * 0.4;
                ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
                ctx.beginPath();
                ctx.arc(pos.x, pos.y, ball.radius * (i / ball.trail.length), 0, Math.PI * 2);
                ctx.fill();
            });

            // Ball
            drawGlowCircle(ball.x, ball.y, ball.radius, ball.color);

            // Player paddle
            drawGlowRect(player.x, player.y, player.width, player.height, player.color);
            // Paddle edge highlight
            ctx.fillStyle = 'rgba(255,255,255,0.3)';
            ctx.fillRect(player.x, player.y, player.width, 2);

            // AI1 paddle
            drawGlowRect(ai1.x, ai1.y, ai1.width, ai1.height, ai1.color);
            ctx.fillStyle = 'rgba(255,255,255,0.3)';
            ctx.fillRect(ai1.x, ai1.y + ai1.height - 2, ai1.width, 2);

            // AI2 paddle (if active)
            if (useAI2) {
                drawGlowRect(ai2.x, ai2.y, ai2.width, ai2.height, ai2.color);
                ctx.fillStyle = 'rgba(255,255,255,0.3)';
                ctx.fillRect(ai2.x + ai2.width - 2, ai2.y, 2, ai2.height);
            }

            // Power-ups
            powerUps.forEach(pu => {
                const pulseR = pu.radius + Math.sin(pu.pulse) * 3;
                let color;
                let symbol;
                switch (pu.type) {
                    case 'expand': color = '#00ff00'; symbol = '⬆'; break;
                    case 'shrink': color = '#ff0000'; symbol = '⬇'; break;
                    case 'fast': color = '#ff8800'; symbol = '⚡'; break;
                    case 'slow': color = '#8800ff'; symbol = '🐌'; break;
                }

                ctx.globalAlpha = Math.min(1, pu.life / 30);
                drawGlowCircle(pu.x, pu.y, pulseR, color + '66');
                ctx.fillStyle = '#fff';
                ctx.font = '16px Arial';
                ctx.textAlign = 'center';
                ctx.fillText(symbol, pu.x, pu.y + 6);
                ctx.globalAlpha = 1;
            });

            // Particles
            particles.forEach(p => {
                if (p.isText) {
                    ctx.globalAlpha = p.life;
                    ctx.fillStyle = p.color;
                    ctx.font = 'bold 18px Arial';
                    ctx.textAlign = 'center';
                    ctx.fillText(p.text, p.x, p.y);
                    ctx.globalAlpha = 1;
                } else {
                    ctx.globalAlpha = p.life;
                    ctx.fillStyle = p.color;
                    ctx.beginPath();
                    ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.globalAlpha = 1;
                }
            });

            // HUD
            drawHUD();

            // Game over overlay
            if (gameState === STATE_GAMEOVER) {
                drawGameOver();
            }
        }

        function drawHUD() {
            // Score panel - top area
            ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
            ctx.fillRect(0, 0, canvas.width, 36);

            ctx.textAlign = 'left';
            ctx.font = 'bold 14px Arial';

            // Player score
            ctx.fillStyle = player.color;
            ctx.fillText(`${playerControlled ? '你' : 'AI-绿'}: ${player.score}`, 10, 24);

            // AI1 score
            ctx.fillStyle = ai1.color;
            ctx.textAlign = 'center';
            ctx.fillText(`${ai1.name}: ${ai1.score}`, 180, 24);

            // AI2 score (if active)
            if (useAI2) {
                ctx.fillStyle = ai2.color;
                ctx.textAlign = 'right';
                ctx.fillText(`${ai2.name}: ${ai2.score}`, 350, 24);
            }

            // Lives
            ctx.textAlign = 'right';
            ctx.fillStyle = '#ff4444';
            let livesText = '';
            for (let i = 0; i < player.lives; i++) livesText += '❤️';
            for (let i = player.lives; i < 3; i++) livesText += '🖤';
            ctx.font = '14px Arial';
            if (!useAI2) ctx.fillText(livesText, 350, 24);

            // Lives below score if AI2 is active
            if (useAI2) {
                ctx.fillStyle = 'rgba(0,0,0,0.3)';
                ctx.fillRect(canvas.width - 80, 36, 80, 20);
                ctx.textAlign = 'right';
                ctx.fillText(livesText, 350, 52);
            }

            // Combo display
            if (comboCount > 1 && comboTimer > 0) {
                ctx.textAlign = 'center';
                ctx.fillStyle = '#ffff00';
                ctx.font = `bold ${16 + comboCount * 2}px Arial`;
                ctx.shadowColor = '#ffff00';
                ctx.shadowBlur = 10;
                ctx.fillText(`🔥 ${comboCount}x 连击!`, 180, canvas.height / 2);
                ctx.shadowBlur = 0;
            }
        }

        function drawGameOver() {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.textAlign = 'center';

            // Determine winner
            const scores = [
                { name: playerControlled ? '你' : 'AI-绿', score: player.score, color: player.color },
                { name: ai1.name, score: ai1.score, color: ai1.color }
            ];
            if (useAI2) scores.push({ name: ai2.name, score: ai2.score, color: ai2.color });
            scores.sort((a, b) => b.score - a.score);

            ctx.fillStyle = '#e94560';
            ctx.font = 'bold 36px Arial';
            ctx.shadowColor = '#e94560';
            ctx.shadowBlur = 20;
            ctx.fillText('游戏结束', 180, 200);
            ctx.shadowBlur = 0;

            // Rankings
            ctx.font = 'bold 20px Arial';
            const medals = ['🥇', '🥈', '🥉'];
            scores.forEach((s, i) => {
                ctx.fillStyle = s.color;
                ctx.fillText(`${medals[i]} ${s.name}: ${s.score}分`, 180, 270 + i * 40);
            });

            if (scores[0].name === '你' || (scores[0].name === 'AI-绿' && !playerControlled)) {
                ctx.fillStyle = '#00ff00';
                ctx.font = 'bold 24px Arial';
                ctx.fillText('🎉 胜利! 🎉', 180, 420);
            } else {
                ctx.fillStyle = '#ff4444';
                ctx.font = 'bold 24px Arial';
                ctx.fillText(`${scores[0].name} 获胜!`, 180, 420);
            }

            ctx.fillStyle = '#aaa';
            ctx.font = '16px Arial';
            ctx.fillText('点击或按空格返回菜单', 180, 480);
        }

        let lastTime = 0;
        function gameLoop(timestamp) {
            const dt = timestamp - lastTime;
            lastTime = timestamp;

            update();
            draw();
            requestAnimationFrame(gameLoop);
        }

        // Increase AI difficulty over time
        setInterval(() => {
            if (gameState === STATE_PLAYING) {
                ai1.speed = Math.min(6, ai1.speed + 0.02);
                ai1.difficulty = Math.min(0.95, ai1.difficulty + 0.005);
                if (useAI2) {
                    ai2.speed = Math.min(5, ai2.speed + 0.015);
                    ai2.difficulty = Math.min(0.9, ai2.difficulty + 0.004);
                }
            }
        }, 3000);

        requestAnimationFrame(gameLoop);
    </script>
